  "split-async": "$id: http://qubership.org/schemas/product/qip/element/split-async.schema.yaml\n$schema: http://json-schema.org/draft-07/schema\ntype: object\nallOf:\n  - $schema: http://json-schema.org/draft-07/schema\n    type: object\n    title: Common element properties\n    properties:\n      id:\n        type: string\n        title: Identifier\n      name:\n        type: string\n        title: Name\n        maxLength: 255\n      description:\n        type: string\n        title: Description\n        maxLength: 255\n      swimlaneId:\n        type: string\n        title: Swimlane Identifier\n    required:\n      - id\n      - name\ntitle: Split Async (deprecated)\nproperties:\n  type:\n    type: string\n    const: split-async\n  children:\n    type: array\n    items:\n      anyOf:\n        - type: object\n        - type: object\nrequired:\n  - type\n",
  "split-async-2": "$id: http://qubership.org/schemas/product/qip/element/split-async-2.schema.yaml\n$schema: http://json-schema.org/draft-07/schema\ntype: object\nallOf:\n  - $schema: http://json-schema.org/draft-07/schema\n    type: object\n    title: Common element properties\n    properties:\n      id:\n        type: string\n        title: Identifier\n      name:\n        type: string\n        title: Name\n        maxLength: 255\n      description:\n        type: string\n        title: Description\n        maxLength: 255\n      swimlaneId:\n        type: string\n        title: Swimlane Identifier\n    required:\n      - id\n      - name\ntitle: Split Async\nproperties:\n  type:\n    type: string\n    const: split-async-2\n  children:\n    type: array\n    items:\n      anyOf:\n        - type: object\nrequired:\n  - type\n",
  "split-element": "$id: http://qubership.org/schemas/product/qip/element/split-element.schema.yaml\n$schema: http://json-schema.org/draft-07/schema\ntype: object\nallOf:\n  - $schema: http://json-schema.org/draft-07/schema\n    type: object\n    title: Common element properties\n    properties:\n      id:\n        type: string\n        title: Identifier\n      name:\n        type: string\n        title: Name\n        maxLength: 255\n      description:\n        type: string\n        title: Description\n        maxLength: 255\n      swimlaneId:\n        type: string\n        title: Swimlane Identifier\n    required:\n      - id\n      - name\ntitle: Split Element (deprecated)\nproperties:\n  type:\n    type: string\n    const: split-element\n  properties:\n    type: object\n    properties:\n      splitName:\n        type: string\n        title: Split Name\n        description: >\n          Define identifier for subchain. Used as name prefix while propagating\n          headers and properties.\n        pattern: ^[-!#-'*+.0-9A-Z^-z|~]+$\n      propagateHeaders:\n        type: boolean\n        title: Propagate headers\n        description: >\n          Propagate headers from this branch. Split name is used as header name\n          prefix.\n        default: false\n      propagateProperties:\n        type: boolean\n        title: Propagate properties\n        description: >\n          Propagate properties from this branch. Split name is used as property\n          name prefix.\n        default: false\n    required:\n      - splitName\n    additionalProperties: false\nrequired:\n  - type\n",
